SELECT COUNT(identifier_id) AS active_identifier_count
FROM identifiers
WHERE word_id = 0 AND status = 'active';

SELECT SUM(usage_count) AS total_usage
FROM usage_stats
WHERE word_id = 1;

SELECT SUM(usage_count) AS total_usage
FROM usage_stats
WHERE word_id = (SELECT word_id FROM words WHERE word_form = 'report');
